const body = $input.first().json.body || $input.first().json;
const id = body.id;
const tenantId = body.tenantId;
const email = body.email;
const nom = body.nom;
const prenom = body.prenom;
const telephone = body.telephone;
const entreprise = body.entreprise;
const tags = body.tags;
const status = body.status;

function esc(v) {
  return v == null ? 'NULL' : "'" + String(v).replace(/'/g, "''") + "'";
}

const updates = [];
if (email !== undefined) updates.push(`email = ${esc(email)}`);
if (nom !== undefined) updates.push(`nom = ${esc(nom)}`);
if (prenom !== undefined) updates.push(`prenom = ${esc(prenom)}`);
if (telephone !== undefined) updates.push(`telephone = ${esc(telephone)}`);
if (entreprise !== undefined) updates.push(`entreprise = ${esc(entreprise)}`);
if (tags !== undefined) updates.push(`tags = ${esc(tags)}`);
if (status !== undefined) updates.push(`status = ${esc(status)}`);
updates.push(`updated_at = NOW()`);

const sql = `UPDATE subscribers SET ${updates.join(', ')} WHERE id = ${esc(id)}::uuid AND tenant_id = ${esc(tenantId)} RETURNING id, tenant_id as tenantId, email, telephone, nom, prenom, entreprise, status, source, tags, created_at as createdAt, updated_at as updatedAt`;

return { sql };

const row = $input.first().json[0] || $input.first().json;

const formatted = {
  subscriber: {
    id: row.id,
    tenantId: row.tenantId,
    email: row.email,
    telephone: row.telephone,
    nom: row.nom,
    prenom: row.prenom,
    entreprise: row.entreprise,
    status: row.status,
    source: row.source,
    tags: row.tags,
    createdAt: row.createdAt,
    updatedAt: row.updatedAt
  }
};

return formatted;
